import subprocess
import sys
import os
import shutil
from pathlib import Path

def run_command(command, check=True):
    try:
        result = subprocess.run(
            command,
            shell=True,
            check=check,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True
        )
        return result
    except subprocess.CalledProcessError as e:
        print(f"Command failed: {command}")
        print(f"Error: {e.stderr}")
        sys.exit(1)

def main():
    # Install dependencies
    print("Installing dependencies...")
    run_command("pip install --no-cache-dir -r requirements.txt")
    
    # Run tests
    print("Running tests...")
    run_command("python -m pytest --tb=short")
    
    # Create deployment package
    print("Creating deployment package...")
    package_dir = Path("dist")
    if package_dir.exists():
        shutil.rmtree(package_dir)
    package_dir.mkdir()
    
    # Copy necessary files
    files_to_copy = ["app.py", "requirements.txt", "config/", "static/", "templates/"]
    for file_path in files_to_copy:
        if os.path.exists(file_path):
            if os.path.isdir(file_path):
                shutil.copytree(file_path, package_dir / file_path)
            else:
                shutil.copy2(file_path, package_dir / file_path)
    
    # Create wheel
    run_command("python setup.py bdist_wheel")
    
    print("Deployment package created successfully.")

if __name__ == "__main__":
    main()